  id: pageId,
  path: pagePath,
  url: pageUrl,
  parentId: pageParentId
})

cms.first({
  workspace,
  root,
  level,

  // Can use a Root, Workspace or a Page as input
  location
})

cms.first({
  // Filter by the schema
  type: BlogPost,
  // Filter using search terms
  search,
  // Filter by fields
  filter: {
    author: 'alinea',
    publishedDate: {
      lt: '2024-01-01',
      gte: '2023-01-01'
    }
  }
})

cms.first({
  // This can be: 'published', 'draft', 'archived', 'preferDraft', 'preferPublished', 'all' 
  status: 'published',
  // Look for result with the exact locale  
  locale: pageLocale 
  // Look for a result with the locale, but ignore when there are no exact matches
  preferredLocale: pageLocale 
})
